"use client";

import { useState, useEffect } from "react";
import { usePathname } from "next/navigation"; // gets URL path
import { collection, query, where, getDocs } from "firebase/firestore";
import { db } from "../../../firebase"; // your firebase config path

export default function ScanPage() {
  const pathname = usePathname(); // e.g., "/scan/QR001"
  const qr_id = pathname.split("/")[2]; // "QR001"

  const [vehicle, setVehicle] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchVehicle = async () => {
      try {
        const q = query(collection(db, "vehicles"), where("qr_id", "==", qr_id));
        const querySnapshot = await getDocs(q);

        if (!querySnapshot.empty) {
          setVehicle(querySnapshot.docs[0].data());
        } else {
          setVehicle(null);
        }
      } catch (error) {
        console.error("Error fetching vehicle:", error);
        setVehicle(null);
      }
      setLoading(false);
    };

    if (qr_id) fetchVehicle();
  }, [qr_id]);

  if (loading) return <p>Loading...</p>;
  if (!vehicle) return <p>QR not registered yet.</p>;

  return (
    <div style={{ padding: "20px", fontFamily: "Arial, sans-serif" }}>
      <h2>Vehicle Details</h2>
      <p><strong>Plate Number:</strong> {vehicle.plate_number}</p>
      <p><strong>Make:</strong> {vehicle.make}</p>
      <p><strong>Model:</strong> {vehicle.model}</p>
    </div>
  );
}